using System;
using System.Threading.Tasks;

static async Task<string> GetGreetingAsync(string name) {
    await Task.Delay(10); // simulate async work
    return $"Hello, {name}!";
}

class Program {
    static async Task Main() {
        string greeting = await GetGreetingAsync("C#");
        Console.WriteLine(greeting);
    }
}

using System;
using System.Threading.Tasks;

static async Task<int> AddAsync(int a, int b) {
    await Task.Delay(1);
    return a + b;
}

class Program {
    static async Task Main() {
        int result = await AddAsync(3, 4);
        Console.WriteLine($"3 + 4 = {result}");
    }
}

using System;
using System.Threading.Tasks;

static async void FireAndForget() {
    await Task.Delay(10);
    Console.WriteLine("Fire and forget completed");
}

class Program {
    static async Task Main() {
        FireAndForget();
        await Task.Delay(50); // wait long enough for it
        Console.WriteLine("Main done");
    }
}

using System;
using System.Threading.Tasks;

static async Task<int> FetchDataAsync(int id) {
    await Task.Delay(10 * id);
    return id * 10;
}

class Program {
    static async Task Main() {
        var tasks = new[] {
            FetchDataAsync(1),
            FetchDataAsync(2),
            FetchDataAsync(3)
        };
        int[] results = await Task.WhenAll(tasks);
        Console.WriteLine(string.Join(" ", results));
    }
}

using System;
using System.Threading.Tasks;

static async Task<string> SlowAsync() {
    await Task.Delay(100);
    return "slow";
}

static async Task<string> FastAsync() {
    await Task.Delay(10);
    return "fast";
}

class Program {
    static async Task Main() {
        Task<string> first = await Task.WhenAny(SlowAsync(), FastAsync());
        Console.WriteLine(await first);
    }
}

using System;
using System.Threading;
using System.Threading.Tasks;

static async Task LongOperationAsync(CancellationToken ct) {
    for (int i = 0; i < 10; i++) {
        ct.ThrowIfCancellationRequested();
        await Task.Delay(10, ct);
        Console.Write($"{i} ");
    }
}

class Program {
    static async Task Main() {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(35));
        try {
            await LongOperationAsync(cts.Token);
        } catch (OperationCanceledException) {
            Console.WriteLine();
            Console.WriteLine("Cancelled!");
        }
    }
}

using System;
using System.Threading.Tasks;

static async ValueTask<int> GetCachedValueAsync(bool useCache) {
    if (useCache) return 42; // synchronous fast path
    await Task.Delay(1);
    return 99;
}

class Program {
    static async Task Main() {
        Console.WriteLine(await GetCachedValueAsync(true));
        Console.WriteLine(await GetCachedValueAsync(false));
    }
}

using System;
using System.Collections.Generic;
using System.Threading.Tasks;

static async IAsyncEnumerable<int> GenerateAsync() {
    for (int i = 1; i <= 5; i++) {
        await Task.Delay(5);
        yield return i;
    }
}

class Program {
    static async Task Main() {
        await foreach (int n in GenerateAsync()) {
            Console.Write($"{n} ");
        }
        Console.WriteLine();
    }
}
